module RefModule(  
    input wire clk_in,  
    input wire rst,  
    output reg clk_out  
);  
    reg [1:0] obf_count;  

    always @(posedge clk_in or posedge rst) begin  
        if (rst) begin  
            obf_count <= 2'b00;  
            clk_out <= 0;  
        end else begin  
            obf_count <= obf_count + 1;  
            if (obf_count == 2'b11) begin  
                clk_out <= ~clk_out;  
            end  
        end  
    end  
endmodule
